SELECT i.ITEM_CD, i.PLANT_CD, i.ITEM_NM, i.ITEM_SPEC, i.ITEM_TYPE, i.ITEM_GRP, i.UNIT, i.SAFETY_STOCK_QTY, i.MAIN_VENDOR_CD, v.VENDOR_NM AS MAIN_VENDOR_NM FROM MST_ITEM i LEFT JOIN MST_VENDOR v ON i.MAIN_VENDOR_CD = v.VENDOR_CD
i.USE_YN = 'Y' AND i.PLANT_CD = #{plantCd} AND i.ITEM_CD LIKE CONCAT('%', #{itemCd}, '%') AND i.ITEM_NM LIKE CONCAT('%', #{itemNm}, '%') AND i.ITEM_TYPE = #{itemType}
ORDER BY i.ITEM_CD
